import{_ as t,o as d,c as e,R as o}from"./chunks/framework.vN7-ZgWj.js";const b=JSON.parse('{"title":"英语基础概念","description":"","frontmatter":{"title":"英语基础概念"},"headers":[],"relativePath":"language/english/basic_concept.md","filePath":"language/english/basic_concept.md","lastUpdated":1714948560000}'),a={name:"language/english/basic_concept.md"},c=o('<div class="danger custom-block"><p class="custom-block-title">✨ 重要的事说三遍</p><p><strong>英文是一门结构性语言！</strong></p><p><strong>英文是一门结构性语言！</strong></p><p><strong>英文是一门结构性语言！</strong></p><p>为什么这么说？因为英文要表达具体的意思时，需要使用固定的 <strong><code>语法结构</code>+<code>单词变化</code></strong> 的形式来实现。这一点和汉语不同，汉语是一种相对更高级的自然语言，中文汉字本身就能直观的表达出意思，不需要乱七八糟的语法结构和单词变化</p></div><h2 id="词性缩写" tabindex="-1">词性缩写 <a class="header-anchor" href="#词性缩写" aria-label="Permalink to &quot;词性缩写&quot;">​</a></h2><table><thead><tr><th>缩写</th><th>原版</th><th>含义</th><th>作用</th></tr></thead><tbody><tr><td>n.</td><td>noun</td><td>名词</td><td>表示人或事物的名称</td></tr><tr><td>un.</td><td>uncountable noun</td><td>不可数名词</td><td></td></tr><tr><td>cn.</td><td>countable noun</td><td>可数名词</td><td></td></tr><tr><td>v.</td><td>verb</td><td>动词</td><td>表示人或事物的动作或状态</td></tr><tr><td>vi.</td><td>intransitive verb</td><td>不及物动词</td><td>本身意思完整，后面不需要跟宾语的动词</td></tr><tr><td>vt.</td><td>transitive verb</td><td>及物动词</td><td>后面必须跟宾语才能使其意思完整的动词</td></tr><tr><td>aux.v.</td><td>auxiliary verb</td><td>助动词</td><td></td></tr><tr><td>link.v.</td><td></td><td>系动词</td><td></td></tr><tr><td>modal.v.</td><td>modal verb</td><td>情态动词</td><td></td></tr><tr><td>conj.</td><td>conjunction</td><td>连接词</td><td>用来连接词、短语或句子</td></tr><tr><td>adj.</td><td>adjective</td><td>形容词</td><td>用来修饰名词，表示人或事物的特征</td></tr><tr><td>adv.</td><td>adverb</td><td>副词</td><td>用来修饰动词、形容词或其他副词，表示动作的特征</td></tr><tr><td>art.</td><td>article</td><td>冠词</td><td>用在名词前，辅助说明名词所指的人或事物</td></tr><tr><td>prep.</td><td>preposition</td><td>介词</td><td>用在名词、代词等前面，说明句子中词与词之间的关系</td></tr><tr><td>pron.</td><td>pronoun</td><td>代词</td><td>用来代替名称、形容词或数词等</td></tr><tr><td>num.</td><td>numeral</td><td>数词</td><td>表示数量或顺序</td></tr><tr><td>int.</td><td>interjection</td><td>感叹词</td><td>表示说话时的感情或口气</td></tr><tr><td>pt.</td><td>past tense</td><td>过去式</td><td></td></tr><tr><td>pp.</td><td>past participle</td><td>过去分词</td><td></td></tr><tr><td>p.pr</td><td>present participle</td><td>现在分词</td><td></td></tr></tbody></table><h2 id="人称代词" tabindex="-1">人称代词 <a class="header-anchor" href="#人称代词" aria-label="Permalink to &quot;人称代词&quot;">​</a></h2><table><thead><tr><th></th><th></th><th>主格</th><th>宾格</th><th>反身代词</th><th>形容词性物主代词</th><th>名词性物主代词</th></tr></thead><tbody><tr><td rowspan="5">单数</td><td>第一人称</td><td>I</td><td>me</td><td>myself</td><td>my</td><td>mine</td></tr><tr><td>第二人称</td><td>you</td><td>you</td><td>yourself</td><td>your</td><td>yours</td></tr><tr><td rowspan="3">第三人称</td><td>he</td><td>him</td><td>himself</td><td>his</td><td>his</td></tr><tr><td>she</td><td>her</td><td>herself</td><td>her</td><td>hers</td></tr><tr><td>it</td><td>it</td><td>itself</td><td>its</td><td>its</td></tr><tr><td rowspan="3">复数</td><td>第一人称</td><td>we</td><td>us</td><td>ourselves</td><td>our</td><td>ours</td></tr><tr><td>第二人称</td><td>you</td><td>you</td><td>yourselves</td><td>your</td><td>yours</td></tr><tr><td>第三人称</td><td>they</td><td>them</td><td>themselves</td><td>their</td><td>theirs</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">⚡</p><p>主格一般作主语，放在句首</p><p>宾格作宾语，放在动词或介词的后面</p><p>形容词性物主代词不能单独使用，后面必须跟名词或其他的词</p><p>名词性物主代词可以单独使用</p></div><h2 id="不定代词" tabindex="-1">不定代词 <a class="header-anchor" href="#不定代词" aria-label="Permalink to &quot;不定代词&quot;">​</a></h2><table><thead><tr><th></th><th>every(每一)</th><th>no(无)</th><th>any(任一)</th><th>some(一些)</th></tr></thead><tbody><tr><td rowspan="3">复合代词</td><td>everyone</td><td>no one</td><td>anyone</td><td>someone</td></tr><tr><td>everybody</td><td>nobody</td><td>anybody</td><td>somebody</td></tr><tr><td>everything</td><td>nowhere</td><td>anywhere</td><td>somewhere</td></tr><tr><td>复合副词</td><td>everywhere</td><td>nothing</td><td>anything</td><td>something</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">⚡</p><p><strong>对于未知的事物通常使用<code>something</code>指代</strong></p><p><strong><code>any-</code></strong> 前缀的不定代词用于疑问句和否定句，<strong><code>some-</code></strong> 前缀的不定代词通常用于肯定句</p><p><strong>-one和-body的区别</strong>：尽管它们的所代表的含义都相同，但在使用时还是有一些细微区别的</p><ul><li><code>-body</code>通常只会用来指代<strong>人</strong>，而<code>-one</code>则可以指代<strong>人</strong>或<strong>物</strong></li></ul><p>不定代词可以作主语、宾语和表语。它后面如果有<code>be</code>动词的话，那只能是单数形式</p><ul><li><p><strong>作主语</strong></p><p>e.g. <code>Everyone is asleep.</code>、<code>Nobody has told me about it.</code></p></li><li><p><strong>作宾语</strong></p><p>e.g. <code>I&#39;ve got nothing to wear.</code>、<code>I saw no one.</code></p></li><li><p><strong>作表语</strong></p><p>e.g. <code>There&#39;s nothing on the table.</code>、<code>There&#39;s somebody in the garden.</code></p></li></ul></div><h2 id="五大句式" tabindex="-1">五大句式 <a class="header-anchor" href="#五大句式" aria-label="Permalink to &quot;五大句式&quot;">​</a></h2><p><strong>S＝主语；V＝谓语；P＝表语；O＝宾语；O1＝间接宾语；O2＝直接宾语；C＝补语</strong></p><table><thead><tr><th>结构</th><th>含义</th><th>例句</th></tr></thead><tbody><tr><td><code>S</code>+<code>V</code></td><td>主谓结构</td><td><code>He runs quickly.</code></td></tr><tr><td><code>S</code>+<code>V</code>+<code>P</code></td><td>主系表结构</td><td><code>The story sounds interesting.</code></td></tr><tr><td><code>S</code>+<code>V</code>+<code>O</code></td><td>主谓宾结构</td><td><code>I love you.</code></td></tr><tr><td><code>S</code>+<code>V</code>+<code>O1</code>+<code>O2</code></td><td>主谓双宾结构</td><td><code>He gave me a book.</code></td></tr><tr><td><code>S</code>+<code>V</code>+<code>O</code>+<code>C</code></td><td>主谓宾补结构</td><td><code>They made the girl angry.</code></td></tr></tbody></table><h2 id="句子成分" tabindex="-1">句子成分 <a class="header-anchor" href="#句子成分" aria-label="Permalink to &quot;句子成分&quot;">​</a></h2><h3 id="词性和句子成分的关系" tabindex="-1">词性和句子成分的关系 <a class="header-anchor" href="#词性和句子成分的关系" aria-label="Permalink to &quot;词性和句子成分的关系&quot;">​</a></h3><p><em>这里的名词是广义上的名词，它包括了名词、代词、数词以及具有名词性质的不定式、动名词、从句(如主语从句)等</em></p><table><thead><tr><th>词性</th><th>句子成分</th><th>从句</th></tr></thead><tbody><tr><td>名</td><td>主/宾/表</td><td>主语/宾语/表语从句</td></tr><tr><td>动</td><td>谓</td><td>谓语没有从句，用副词修饰</td></tr><tr><td>形</td><td>定</td><td>定语从句</td></tr><tr><td>副</td><td>状</td><td>状语从句</td></tr></tbody></table><h3 id="主语" tabindex="-1">主语 <a class="header-anchor" href="#主语" aria-label="Permalink to &quot;主语&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡主语是句子中执行动作或被描述的对象，通常位于句首，也可以是句中或句尾。可以理解为，这个句子围绕谁展开，谁就是主语</p><p>主语可以由名词、代词、数词、不定式、动名词、从句(如主语从句)或it(作为形式主语)担任</p><p>e.g. <code>I study english.</code></p><p><strong><code>I</code></strong> 是主语，这个句子围绕「我」做什么展开</p></div><h3 id="系动词" tabindex="-1">系动词 <a class="header-anchor" href="#系动词" aria-label="Permalink to &quot;系动词&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡这种词没有具体的动作，只是起连接主语和后面成分的作用</p><p>常见的系动词有：<code>be</code>、<code>look</code>、<code>feel</code>、<code>sound</code>、<code>smell</code>、<code>taste</code>、<code>seem</code>、<code>become</code>、<code>turn</code>、<code>grow</code>、<code>get</code>、<code>go</code>、<code>fall</code></p></div><h3 id="表语" tabindex="-1">表语 <a class="header-anchor" href="#表语" aria-label="Permalink to &quot;表语&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡又叫主语补足语，对主语进行补充说明，是紧跟在系动词后面的成分</p><p>e.g. <code>I am a student.</code></p><p><strong><code>a student</code></strong> 是表语，对主语 <strong><code>I</code></strong> 的补充</p></div><h3 id="谓语" tabindex="-1">谓语 <a class="header-anchor" href="#谓语" aria-label="Permalink to &quot;谓语&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡谓语用于说明主语的状态或执行的动作，通常紧跟在主语之后。谓语由动词构成，是句子中时态和语态变化的主角</p><p>e.g. <code>I drink water.</code></p><p><strong><code>drink</code></strong> 是谓语，主语 <strong><code>I</code></strong> 发出的动作</p></div><h3 id="宾语" tabindex="-1">宾语 <a class="header-anchor" href="#宾语" aria-label="Permalink to &quot;宾语&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡宾语是句子中动作的接受者或受益者，通常位于谓语动词之后。宾语可以是名词或代词，且代词必须是宾格形式</p><p>e.g. <code>These children are playing football.</code></p><p><strong><code>football</code></strong> 是宾语，是动作 <strong><code>play</code></strong> 的作用对象</p></div><h4 id="双宾语" tabindex="-1">双宾语 <a class="header-anchor" href="#双宾语" aria-label="Permalink to &quot;双宾语&quot;">​</a></h4><div class="danger custom-block"><p class="custom-block-title">⚡宾语包含两部分，「<strong>直接宾语</strong>」和「<strong>间接宾语</strong>」</p><ul><li><strong>直接宾语(物)</strong>：是动作的承受者</li><li><strong>间接宾语(人)</strong>：表示动作的方向(对谁做)、或动作的目标(为谁做)。一般紧跟在谓语动词后面</li></ul><p>常见句型结构：<strong><code>主语</code>+<code>谓语(及物动词)</code>+<code>间接宾语</code>+<code>直接宾语</code></strong></p></div><h3 id="定语" tabindex="-1">定语 <a class="header-anchor" href="#定语" aria-label="Permalink to &quot;定语&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡形容词修饰名词作定语</p><p>定语是用来修饰名词或代词的词汇，通常位于被修饰词之前(前置定语)，但也可以做后置定语</p><p>定语可以是形容词、名词、数词、介词短语、不定式、从句(如定语从句)等</p><p>e.g. <code>I don&#39;t know the man over there.</code></p><p><strong><code>over there</code></strong> 是后置定语，修饰 <strong><code>the man</code></strong></p></div><h3 id="状语" tabindex="-1">状语 <a class="header-anchor" href="#状语" aria-label="Permalink to &quot;状语&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡副词修饰动词作状语</p><p>状语用来修饰动词、形容词、其他副词或整个句子，表示时间、地点、原因、结果、目的、条件、程度、方式等概念</p><p>状语通常是副词，但也可以是不定式、介词、名词、从句等</p><p>e.g. <code>He is very fat.</code></p><p><strong><code>very</code></strong> 是状语，修饰 <strong><code>fat</code></strong></p></div><h3 id="补语" tabindex="-1">补语 <a class="header-anchor" href="#补语" aria-label="Permalink to &quot;补语&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">⚡本质上是对动词进行补充说明</p><p>补语分为：「<strong>宾语补足语</strong>」和「<strong>主语补足语</strong>」</p><p>前面的<a href="#表语">表语</a>已经解释过，表语又叫主语补足语，是对主语的补充说明</p><p>那么宾语补足语就是对宾语的补充说明</p><p>e.g. <code>You should keep the room clean and tidy.</code></p><p><strong><code>clean and tidy</code></strong> 是宾语补足语，对宾语 <strong><code>the room</code></strong> 进行补充说明；同时还是对实义动词 <strong><code>keep</code></strong> 的补充说明</p></div><h2 id="名词性从句" tabindex="-1">名词性从句 <a class="header-anchor" href="#名词性从句" aria-label="Permalink to &quot;名词性从句&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡在句子中起名词作用的从句</p><p>它可以分为主语从句、表语从句、宾语从句和同位语从句</p></div><h3 id="主语从句" tabindex="-1">主语从句 <a class="header-anchor" href="#主语从句" aria-label="Permalink to &quot;主语从句&quot;">​</a></h3><p>一个句子在整个句子中充当主语的成分。通常由<code>that</code>、<code>whether</code>、<code>what</code>、<code>who</code>、<code>which</code>、<code>how</code>、<code>when</code>、<code>where</code>、<code>why</code>等引导，<strong>放在谓语动词之前</strong></p><p>e.g. <code>What he said is true.</code></p><h3 id="表语从句" tabindex="-1">表语从句 <a class="header-anchor" href="#表语从句" aria-label="Permalink to &quot;表语从句&quot;">​</a></h3><p>一个句子在整个句子中充当表语的成分。通常由<code>that</code>、<code>whether</code>、<code>what</code>、<code>who</code>、<code>which</code>、<code>how</code>、<code>when</code>、<code>where</code>、<code>why</code>等引导，<strong>放在系动词之后</strong></p><p>e.g. <code>The problem is how we can solve it.</code></p><h3 id="宾语从句" tabindex="-1">宾语从句 <a class="header-anchor" href="#宾语从句" aria-label="Permalink to &quot;宾语从句&quot;">​</a></h3><p>一个句子在整个句子中充当宾语的成分。通常由<code>that</code>、<code>if</code>、<code>whether</code>、<code>what</code>、<code>who</code>、<code>which</code>、<code>how</code>、<code>when</code>、<code>where</code>、<code>why</code>等引导，<strong>放在及物动词或介词之后</strong></p><p>e.g. <code>I don’t know whether he will come.</code></p><h3 id="同位语从句" tabindex="-1">同位语从句 <a class="header-anchor" href="#同位语从句" aria-label="Permalink to &quot;同位语从句&quot;">​</a></h3><p>一个句子在整个句子中充当同位语的成分。通常由<code>that</code>引导，<strong>放在某些名词之后</strong>，对名词进行解释或说明</p><p>e.g. <code>The news that he passed the exam made us happy.</code></p><h2 id="形容性从句" tabindex="-1">形容性从句 <a class="header-anchor" href="#形容性从句" aria-label="Permalink to &quot;形容性从句&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡在句子中起形容词作用的从句</p><p>也叫定语从句，一个句子在整个句子中充当定语的成分，它用来修饰先行词(<em>即名词或代词</em>)。通常由关系代词<code>who</code>、<code>whom</code>、<code>whose</code>、<code>which</code>、<code>that</code>或关系副词<code>when</code>、<code>where</code>、<code>why</code>引导，<strong>放在先行词之后</strong></p></div><h3 id="限定性定语从句" tabindex="-1">限定性定语从句 <a class="header-anchor" href="#限定性定语从句" aria-label="Permalink to &quot;限定性定语从句&quot;">​</a></h3><p>对先行词起到限定作用的定语从句，它是句子的必要成分，不能省略，也不用逗号分隔</p><p>e.g. <code>The man who is talking to my father is a teacher.</code></p><h3 id="非限定性定语从句" tabindex="-1">非限定性定语从句 <a class="header-anchor" href="#非限定性定语从句" aria-label="Permalink to &quot;非限定性定语从句&quot;">​</a></h3><p>对先行词起到补充说明作用的定语从句，它是句子的非必要成分，可以省略，要用逗号分隔</p><p>e.g. <code>My brother, who lives in Beijing, is a doctor.</code></p><h2 id="副词性从句" tabindex="-1">副词性从句 <a class="header-anchor" href="#副词性从句" aria-label="Permalink to &quot;副词性从句&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">⚡在句子中起副词作用的从句</p><p>也叫状语从句，一个句子在整个句子中充当状语的成分，它用来修饰主句的谓语或整个句子，表示<code>时间</code>、<code>地点</code>、<code>原因</code>、<code>目的</code>、<code>结果</code>、<code>条件</code>、<code>方式</code>、<code>比较</code>、<code>让步</code>等。通常由各种从属连词引导，<strong>放在主句之前或之后</strong></p></div><h3 id="时间状语从句" tabindex="-1">时间状语从句 <a class="header-anchor" href="#时间状语从句" aria-label="Permalink to &quot;时间状语从句&quot;">​</a></h3><p>e.g. <code>When I got home, I found the door open.</code></p><h3 id="地点状语从句" tabindex="-1">地点状语从句 <a class="header-anchor" href="#地点状语从句" aria-label="Permalink to &quot;地点状语从句&quot;">​</a></h3><p>e.g. <code>He went to the library where he could find the book.</code></p><h3 id="原因状语从句" tabindex="-1">原因状语从句 <a class="header-anchor" href="#原因状语从句" aria-label="Permalink to &quot;原因状语从句&quot;">​</a></h3><p>e.g. <code>Because it was raining, we stayed at home.</code></p><h3 id="目的状语从句" tabindex="-1">目的状语从句 <a class="header-anchor" href="#目的状语从句" aria-label="Permalink to &quot;目的状语从句&quot;">​</a></h3><p>e.g. <code>He studied hard so that he could pass the exam.</code></p><h3 id="结果状语从句" tabindex="-1">结果状语从句 <a class="header-anchor" href="#结果状语从句" aria-label="Permalink to &quot;结果状语从句&quot;">​</a></h3><p>e.g. <code>He was so tired that he fell asleep at once.</code></p><h3 id="条件状语从句" tabindex="-1">条件状语从句 <a class="header-anchor" href="#条件状语从句" aria-label="Permalink to &quot;条件状语从句&quot;">​</a></h3><p>e.g. <code>If you work hard, you will succeed.</code></p><h3 id="方式状语从句" tabindex="-1">方式状语从句 <a class="header-anchor" href="#方式状语从句" aria-label="Permalink to &quot;方式状语从句&quot;">​</a></h3><p>e.g. <code>He did it as I told him.</code></p><h3 id="比较状语从句" tabindex="-1">比较状语从句 <a class="header-anchor" href="#比较状语从句" aria-label="Permalink to &quot;比较状语从句&quot;">​</a></h3><p>e.g. <code>She is taller than I am.</code></p><h3 id="让步状语从句" tabindex="-1">让步状语从句 <a class="header-anchor" href="#让步状语从句" aria-label="Permalink to &quot;让步状语从句&quot;">​</a></h3><p>e.g. <code>Although he is old, he is still healthy.</code></p>',76),r=[c];function s(h,n,l,i,p,u){return d(),e("div",null,r)}const m=t(a,[["render",s]]);export{b as __pageData,m as default};
